import React from 'react';
import styles from './card-testimonial.module.css';

interface CardProps {
    imgSrc: string;
    review: string;
    author: string;
    starSrc: string;
}

const CardTestimonial: React.FC<CardProps>  = ({ imgSrc, review, author, starSrc }) => {
  return (
    <div className={styles.card_testimonial}>
        <div className={styles.container_inner}>
            <div className={styles.image_container}>

            </div>
            <img className={styles.profile} src={imgSrc} alt="profile" width={84} height={84} />
            <img className={styles.stars} src={starSrc} alt="stars" />
            <p className={styles.review}>{review}</p>
            <p className={styles.author}>{author}</p>
        </div>

    </div>
  )
}

export default CardTestimonial;
